import { BaseRepository } from './base.repository';
import { IUserRepository } from './interfaces/IUser.repository';
import User, { IUser } from '../models/user.model';
import { Role } from '@/types/role.types';
import { UserUpdateData } from '@/types/repository.types';
import { ISubscription } from '@/models/subscription.model';
import { FilterQuery } from 'mongoose';

export class UserRepository
    extends BaseRepository<IUser>
    implements IUserRepository
{
    constructor() {
        super(User);
    }

    async findByEmail(email: string): Promise<IUser | null> {
        return await this.findOne({ email });
    }

    async createUser(data: {
        email: string;
        password: string;
        name: string;
        role: Role.User;
        googleId?: string;
    }): Promise<IUser> {
        return this.create(data);
    }
    async findById(id: string): Promise<IUser | null> {
        return await User.findById(id);
    }

    async updatePasswordById(
        userId: string,
        newPassword: string
    ): Promise<void> {
        await User.updateOne(
            { _id: userId },
            { $set: { password: newPassword } }
        );
    }

    async updateSubscriptionByEmail(
        email: string,
        subscriptionData: ISubscription
    ): Promise<IUser | null> {
        return User.findOneAndUpdate(
            { email },
            { $set: { subscription: subscriptionData } },
            { new: true }
        );
    }

    async updateSubscriptionById(
        userId: string,
        subscriptionData: ISubscription
    ): Promise<IUser | null> {
        return User.findByIdAndUpdate(
            userId,
            { $set: { subscription: subscriptionData } },
            { new: true }
        );
    }

    async findByStripeCustomerId(customerId: string): Promise<IUser | null> {
        return User.findOne({ stripeCustomerId: customerId }).exec();
    }

    async updateUser(
        id: string,
        updatedData: UserUpdateData
    ): Promise<IUser | null> {
        const updatedUser = await User.findByIdAndUpdate(
            id,
            { ...updatedData },
            { new: true, runValidators: true }
        ).exec();
        return updatedUser;
    }

    async updateProfilePic(id: string, fileUrl: string): Promise<IUser | null> {
        const updatedUser = await User.findByIdAndUpdate(
            id,
            { profilePic: fileUrl },
            { new: true, runValidators: true }
        ).exec();

        return updatedUser;
    }

    async getAllUsers(
        page: number,
        limit: number,
        search?: string
    ): Promise<{ users: IUser[]; totalCount: number }> {
        const skip = (page - 1) * limit;
        const query: FilterQuery<IUser> = { role: Role.User };

        if (search) {
            query.$or = [
                { name: { $regex: search, $options: 'i' } },
                { email: { $regex: search, $options: 'i' } },
            ];
        }

        const [users, totalCount] = await Promise.all([
            User.find(query)
                .skip(skip)
                .limit(limit)
                .sort({ createdAt: -1 })
                .exec(),
            User.countDocuments(query),
        ]);
        return { users, totalCount };
    }
}
